const STEPS = [
    {
        id: 'meet',
        eyebrow: '01 — The Beginning',
        headline: 'Your entire wardrobe.\nIn your pocket.',
        sub: 'Fluntr digitises everything you own into a living, breathing digital closet. No more guessing. No more chaos.',
        tag: 'Meet Fluntr',
        screen: 'splash',
        accent: '#C9A84C',
    },
    {
        id: 'snap',
        eyebrow: '02 — Add to Closet',
        headline: 'Pick from your gallery.\nOne tap.',
        sub: 'Open Fluntr, tap Closet, and select any photo from your phone. Your clothes, your camera roll — now your digital wardrobe.',
        tag: 'Select & Add',
        screen: 'gallery_selected',
        accent: '#fff',
    },
    {
        id: 'ai',
        eyebrow: '03 — AI Processing',
        headline: 'AI strips the background.\nInstantly.',
        sub: 'Our AI isolates your clothing item in milliseconds. Clean, precise, professional — every single time. No editing needed.',
        tag: 'AI Magic',
        screen: 'ai',
        accent: '#C9A84C',
    },
    {
        id: 'tag',
        eyebrow: '04 — Smart Tagging',
        headline: 'Category. Collection.\nBrand. All auto-filled.',
        sub: 'Fluntr reads your item and pre-fills the details. Set the category, pick a collection, add a link — then hit Next.',
        tag: 'Tag It',
        screen: 'details',
        accent: '#fff',
    },
    {
        id: 'closet',
        eyebrow: '05 — Your Closet',
        headline: 'It appears in your closet.\nOrganised. Beautiful.',
        sub: 'Every item you add lives here — sorted by collection, occasion, category. Your wardrobe has never looked this good.',
        tag: 'Done',
        screen: 'closet',
        accent: '#C9A84C',
    },
]


const IMGS = {
    splash: "data:image/jpeg;base64,",
    gallery_selected: "data:image/jpeg;base64,",
    details: "data:image/jpeg;base64,",
    closet: "data:image/jpeg;base64,",
}


function AIRemovalScreen() {
    const [phase, setPhase] = useState(0)
    useEffect(() => {
        const t1 = setTimeout(() => setPhase(1), 600)
        const t2 = setTimeout(() => setPhase(2), 1800)
        const t3 = setTimeout(() => setPhase(3), 3000)
        const t4 = setTimeout(() => { setPhase(0); }, 4500)
        return () => { clearTimeout(t1); clearTimeout(t2); clearTimeout(t3); clearTimeout(t4) }
    }, [])

    return (
        <div style={{
            width: '100%', height: '100%',
            background: '#0a0a0a',
            display: 'flex', flexDirection: 'column',
            alignItems: 'center', justifyContent: 'center',
            padding: '24px 20px',
            fontFamily: "'Jost', sans-serif",
        }}>
            {/* Top bar */}
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', width: '100%', marginBottom: '20px' }}>
                <span style={{ fontSize: '12px', color: 'rgba(255,255,255,0.4)' }}>← back</span>
                <span style={{ fontSize: '13px', color: '#fff', fontWeight: 500 }}>Processing</span>
                <span style={{ fontSize: '12px', color: 'rgba(255,255,255,0)' }}>next</span>
            </div>

            {/* Main canvas */}
            <div style={{
                width: '100%', aspectRatio: '3/4',
                borderRadius: '16px',
                position: 'relative', overflow: 'hidden',
                background: phase >= 2 ? '#f8f6f2' : '#1a1a1a',
                transition: 'background 0.8s ease',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
            }}>
                {/* Checkerboard bg when clean */}
                {phase >= 2 && (
                    <div style={{
                        position: 'absolute', inset: 0,
                        backgroundImage: 'linear-gradient(45deg, #e8e8e8 25%, transparent 25%), linear-gradient(-45deg, #e8e8e8 25%, transparent 25%), linear-gradient(45deg, transparent 75%, #e8e8e8 75%), linear-gradient(-45deg, transparent 75%, #e8e8e8 75%)',
                        backgroundSize: '20px 20px',
                        backgroundPosition: '0 0, 0 10px, 10px -10px, -10px 0px',
                        opacity: 0.3,
                    }} />
                )}

                {/* Dress SVG illustration */}
                <motion.div
                    animate={{
                        opacity: phase === 0 ? 0.3 : 1,
                        filter: phase >= 2 ? 'drop-shadow(0 20px 40px rgba(0,0,0,0.15))' : 'none',
                    }}
                    transition={{ duration: 0.8 }}
                    style={{ position: 'relative', zIndex: 2 }}
                >
                    <svg viewBox="0 0 160 220" width="140" xmlns="http://www.w3.org/2000/svg">
                        {/* Dress body */}
                        <path d="M50 40 L30 80 L20 180 L140 180 L130 80 L110 40 Z" fill={phase >= 2 ? "#f5e6d3" : "#888"} stroke={phase >= 2 ? "#d4a574" : "#666"} strokeWidth="2" />
                        {/* Neckline */}
                        <path d="M60 40 Q80 55 100 40" fill="none" stroke={phase >= 2 ? "#c4956a" : "#666"} strokeWidth="2.5" />
                        {/* Left strap */}
                        <path d="M60 40 L55 20 Q60 15 65 18 L68 40" fill={phase >= 2 ? "#e8c99a" : "#777"} stroke={phase >= 2 ? "#c4956a" : "#666"} strokeWidth="1.5" />
                        {/* Right strap */}
                        <path d="M100 40 L105 20 Q100 15 95 18 L92 40" fill={phase >= 2 ? "#e8c99a" : "#777"} stroke={phase >= 2 ? "#c4956a" : "#666"} strokeWidth="1.5" />
                        {/* Waist detail */}
                        <path d="M35 110 Q80 120 125 110" fill="none" stroke={phase >= 2 ? "#c4956a" : "#666"} strokeWidth="1.5" strokeDasharray="4,3" />
                        {/* Bottom trim wavy */}
                        <path d="M20 165 Q35 158 50 165 Q65 172 80 165 Q95 158 110 165 Q125 172 140 165" fill="none" stroke={phase >= 2 ? "#c4956a" : "#666"} strokeWidth="2" />
                        <path d="M20 172 Q35 165 50 172 Q65 179 80 172 Q95 165 110 172 Q125 179 140 172" fill="none" stroke={phase >= 2 ? "#c4956a" : "#666"} strokeWidth="2" />
                    </svg>
                </motion.div>

                {/* Scan line */}
                {phase === 1 && (
                    <motion.div
                        initial={{ top: '0%' }}
                        animate={{ top: '100%' }}
                        transition={{ duration: 1.2, ease: 'linear' }}
                        style={{
                            position: 'absolute', left: 0, right: 0,
                            height: '2px',
                            background: 'linear-gradient(90deg, transparent, #C9A84C, transparent)',
                            boxShadow: '0 0 20px rgba(201,168,76,0.8)',
                            zIndex: 10,
                        }}
                    />
                )}

                {/* Processing overlay */}
                {phase === 1 && (
                    <div style={{
                        position: 'absolute', inset: 0, zIndex: 5,
                        background: 'rgba(201,168,76,0.04)',
                    }} />
                )}

                {/* Done checkmark */}
                {phase >= 3 && (
                    <motion.div
                        initial={{ scale: 0, opacity: 0 }}
                        animate={{ scale: 1, opacity: 1 }}
                        transition={{ type: 'spring', stiffness: 300, damping: 20 }}
                        style={{
                            position: 'absolute', top: 12, right: 12,
                            width: '32px', height: '32px',
                            background: '#C9A84C', borderRadius: '50%',
                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                            zIndex: 20, fontSize: '16px',
                        }}
                    >✓</motion.div>
                )}
            </div>

            {/* Status bar */}
            <div style={{ width: '100%', marginTop: '16px' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '8px' }}>
                    <span style={{ fontSize: '11px', color: 'rgba(255,255,255,0.6)', fontFamily: "'Jost',sans-serif" }}>
                        {['Analysing image...', 'Removing background...', 'Background removed ✦', 'Ready to save ✦'][Math.min(phase, 3)]}
                    </span>
                    <span style={{ fontSize: '11px', color: '#C9A84C' }}>{[0, 35, 90, 100][Math.min(phase, 3)]}%</span>
                </div>
                <div style={{ height: '2px', background: 'rgba(255,255,255,0.08)', borderRadius: '2px', overflow: 'hidden' }}>
                    <motion.div
                        animate={{ width: ['0%', '35%', '90%', '100%'][Math.min(phase, 3)] }}
                        transition={{ duration: 0.8, ease: 'easeOut' }}
                        style={{ height: '100%', background: 'linear-gradient(90deg, #C9A84C, #E2C97E)', borderRadius: '2px' }}
                    />
                </div>
            </div>

            {/* Tags appearing */}
            {phase >= 3 && (
                <motion.div
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ duration: 0.5 }}
                    style={{ display: 'flex', gap: '8px', marginTop: '14px', flexWrap: 'wrap' }}
                >
                    {['Top', 'Beige', 'Summer'].map((tag, i) => (
                        <motion.span
                            key={tag}
                            initial={{ opacity: 0, scale: 0.8 }}
                            animate={{ opacity: 1, scale: 1 }}
                            transition={{ delay: i * 0.1 }}
                            style={{
                                fontSize: '11px', padding: '4px 12px',
                                background: 'rgba(201,168,76,0.12)',
                                border: '0.5px solid rgba(201,168,76,0.3)',
                                color: '#C9A84C', borderRadius: '20px',
                                fontFamily: "'Jost',sans-serif",
                            }}
                        >{tag}</motion.span>
                    ))}
                </motion.div>
            )}
        </div>
    )
}

function PhoneFrame({ screen, isActive }) {
    const [aiKey, setAiKey] = useState(0)

    useEffect(() => {
        if (screen === 'ai' && isActive) {
            setAiKey(k => k + 1)
        }
    }, [screen, isActive])

    return (
        <div style={{
            width: '260px',
            borderRadius: '44px',
            overflow: 'hidden',
            background: '#000',
            border: '1px solid rgba(255,255,255,0.12)',
            boxShadow: '0 60px 120px rgba(0,0,0,0.8), 0 0 0 0.5px rgba(255,255,255,0.05)',
            position: 'relative',
            flexShrink: 0,
        }}>
            {/* Dynamic island */}
            <div style={{
                position: 'absolute', top: '12px', left: '50%',
                transform: 'translateX(-50%)',
                width: '100px', height: '30px',
                background: '#000', borderRadius: '20px',
                zIndex: 30,
                border: '1px solid rgba(255,255,255,0.08)',
            }} />

            <div style={{ width: '100%', aspectRatio: '9/19.5', position: 'relative', overflow: 'hidden' }}>
                <AnimatePresence mode="wait">
                    <motion.div
                        key={screen}
                        initial={{ opacity: 0, scale: 1.02 }}
                        animate={{ opacity: 1, scale: 1 }}
                        exit={{ opacity: 0, scale: 0.98 }}
                        transition={{ duration: 0.5, ease: [0.22, 1, 0.36, 1] }}
                        style={{ position: 'absolute', inset: 0 }}
                    >
                        {screen === 'ai'
                            ? <AIRemovalScreen key={aiKey} />
                            : <img src={IMGS[screen]} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover', display: 'block' }} />
                        }
                    </motion.div>
                </AnimatePresence>
            </div>
        </div>
    )
}

export default function CinematicScroll() {
    const containerRef = useRef(null)
    const [activeStep, setActiveStep] = useState(0)
    const [scrollProgress, setScrollProgress] = useState(0)

    useEffect(() => {
        const handleScroll = () => {
            if (!containerRef.current) return
            const rect = containerRef.current.getBoundingClientRect()
            const sectionHeight = containerRef.current.scrollHeight - window.innerHeight
            const scrolled = -rect.top
            const progress = Math.max(0, Math.min(1, scrolled / sectionHeight))
            setScrollProgress(progress)
            const step = Math.min(STEPS.length - 1, Math.floor(progress * STEPS.length))
            setActiveStep(step)
        }
        window.addEventListener('scroll', handleScroll, { passive: true })
        return () => window.removeEventListener('scroll', handleScroll)
    }, [])

    const current = STEPS[activeStep]

    return (
        <section
            ref={containerRef}
            style={{
                height: `${STEPS.length * 120}vh`,
                background: '#050505',
                position: 'relative',
            }}
        >
            {/* Sticky container */}
            <div style={{
                position: 'sticky', top: 0,
                height: '100vh',
                display: 'flex', flexDirection: 'column',
                alignItems: 'center', justifyContent: 'center',
                overflow: 'hidden',
                padding: '0 24px',
            }}>

                {/* Background glow */}
                <motion.div
                    animate={{
                        background: activeStep % 2 === 0
                            ? 'radial-gradient(ellipse at 30% 50%, rgba(201,168,76,0.06) 0%, transparent 60%)'
                            : 'radial-gradient(ellipse at 70% 50%, rgba(201,168,76,0.04) 0%, transparent 60%)'
                    }}
                    transition={{ duration: 1 }}
                    style={{ position: 'absolute', inset: 0, pointerEvents: 'none' }}
                />

                {/* Progress dots */}
                <div style={{
                    position: 'absolute', top: '28px', left: '50%',
                    transform: 'translateX(-50%)',
                    display: 'flex', gap: '8px', zIndex: 10,
                }}>
                    {STEPS.map((_, i) => (
                        <motion.div
                            key={i}
                            animate={{
                                width: i === activeStep ? '24px' : '6px',
                                background: i === activeStep ? '#C9A84C' : 'rgba(255,255,255,0.2)',
                            }}
                            transition={{ duration: 0.3 }}
                            style={{ height: '6px', borderRadius: '3px' }}
                        />
                    ))}
                </div>

                {/* Main layout — mobile stacked, desktop side by side */}
                <div style={{
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    gap: '32px',
                    width: '100%',
                    maxWidth: '1100px',
                    paddingTop: '48px',
                }}>
                    {/* Phone */}
                    <motion.div
                        animate={{ y: activeStep % 2 === 0 ? 0 : -8 }}
                        transition={{ duration: 0.8, ease: [0.22, 1, 0.36, 1] }}
                    >
                        <PhoneFrame screen={current.screen} isActive={true} />
                    </motion.div>

                    {/* Text */}
                    <AnimatePresence mode="wait">
                        <motion.div
                            key={activeStep}
                            initial={{ opacity: 0, y: 24 }}
                            animate={{ opacity: 1, y: 0 }}
                            exit={{ opacity: 0, y: -24 }}
                            transition={{ duration: 0.5, ease: [0.22, 1, 0.36, 1] }}
                            style={{ textAlign: 'center', maxWidth: '400px' }}
                        >
                            <motion.span
                                style={{
                                    display: 'inline-block',
                                    fontSize: '10px',
                                    letterSpacing: '0.3em',
                                    textTransform: 'uppercase',
                                    color: '#C9A84C',
                                    marginBottom: '12px',
                                    fontFamily: "'Jost', sans-serif",
                                    fontWeight: 400,
                                }}
                            >
                                {current.eyebrow}
                            </motion.span>

                            <h2 style={{
                                fontFamily: "'Cormorant Garamond', serif",
                                fontSize: 'clamp(32px, 7vw, 52px)',
                                fontWeight: 300,
                                lineHeight: 1.1,
                                color: '#ffffff',
                                letterSpacing: '-0.5px',
                                marginBottom: '16px',
                                whiteSpace: 'pre-line',
                            }}>
                                {current.headline}
                            </h2>

                            <p style={{
                                fontFamily: "'Jost', sans-serif",
                                fontSize: '14px',
                                color: 'rgba(255,255,255,0.52)',
                                lineHeight: 1.8,
                                fontWeight: 300,
                                letterSpacing: '0.01em',
                                marginBottom: '20px',
                            }}>
                                {current.sub}
                            </p>

                            {/* Step tag pill */}
                            <motion.div
                                whileHover={{ scale: 1.04 }}
                                style={{
                                    display: 'inline-flex',
                                    alignItems: 'center',
                                    gap: '8px',
                                    padding: '8px 20px',
                                    background: 'rgba(201,168,76,0.08)',
                                    border: '0.5px solid rgba(201,168,76,0.25)',
                                    borderRadius: '40px',
                                    fontSize: '11px',
                                    color: '#C9A84C',
                                    fontFamily: "'Jost', sans-serif",
                                    letterSpacing: '0.15em',
                                    textTransform: 'uppercase',
                                }}
                            >
                                <span style={{ width: '6px', height: '6px', borderRadius: '50%', background: '#C9A84C', display: 'inline-block' }} />
                                {current.tag}
                            </motion.div>
                        </motion.div>
                    </AnimatePresence>
                </div>

                {/* Scroll indicator */}
                <div style={{
                    position: 'absolute', bottom: '28px', left: '50%',
                    transform: 'translateX(-50%)',
                    display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '8px',
                }}>
                    <div style={{
                        width: '1px', height: '40px',
                        background: 'rgba(255,255,255,0.1)',
                        position: 'relative', overflow: 'hidden',
                    }}>
                        <motion.div
                            animate={{ y: ['0%', '100%'] }}
                            transition={{ duration: 1.5, repeat: Infinity, ease: 'linear' }}
                            style={{
                                position: 'absolute', top: 0, left: 0, right: 0,
                                height: '40%',
                                background: 'linear-gradient(to bottom, transparent, #C9A84C, transparent)',
                            }}
                        />
                    </div>
                    <span style={{
                        fontSize: '9px', letterSpacing: '0.2em',
                        color: 'rgba(255,255,255,0.25)',
                        textTransform: 'uppercase',
                        fontFamily: "'Jost', sans-serif",
                    }}>
                        {activeStep < STEPS.length - 1 ? 'scroll' : 'continue'}
                    </span>
                </div>
            </div>
        </section>
    )
}
